#!/usr/bin/perl -wT

use strict;
use warnings;
use CGI qw/:standard/;

my $query = new CGI;
my $logfile = $query->param('logfile');
my $log_dir = '/path/to/log/files';

print "Content-type:text/html\n\n";

if ($logfile) {
    open(my $FH, "<$log_dir/$logfile") or die "Can't open file: $!";
    while (my $line = <$FH>) {
        print "$line";
    }
} else {
    print "Please provide a log file name.";
}

sub show_error {
    my ($message) = @_;
    print qq{
        <h2>Error</h2>
        <p>$message</p>
    };
}